    fn sphere(p: vec3<f32>, diameter: f32) -> f32 {
      return length(p) - (diameter / 2.0);
    }
    fn circle(p: vec2<f32>, diameter: f32) -> f32 {
      return length(p) - (diameter / 2.0);
